diff --git a/core/deployment/src/main/java/io/quarkiverse/mcp/server/deployment/JsonSchemaGeneratorProcessor.java b/core/deployment/src/main/java/io/quarkiverse/mcp/server/deployment/JsonSchemaGeneratorProcessor.java
